import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(pos1, pos2):
        return np.linalg.norm(pos1 - pos2) / truck_speed

    def time_window_priority(time_window, current_time):
        if current_time < time_window[0]:
            return time_window[0] - current_time  # Prioritize customers whose window is starting soon
        elif time_window[0] <= current_time <= time_window[1]:
            return 0  # High priority for customers currently within their window
        else:
            return float('inf')  # Very low priority if the window is missed

    # Cluster customers based on proximity using a simple centroid-based heuristic
    if len(unvisited_customers) > 0:
        cluster_centers = [np.mean(np.array(unvisited_customers), axis=0)]
        clusters = {0: unvisited_customers}
    else:
        cluster_centers = []
        clusters = {}

    nearest_cluster = None
    minimal_time_to_start = float('inf')

    # Evaluate each cluster
    for idx, center in enumerate(cluster_centers):
        travel_time_to_cluster = calculate_travel_time(cur_truck_pos, center)
        # Determine the earliest start time within this cluster
        cluster_start_time = min([time_window_priority(time_windows[i], current_time + travel_time_to_cluster) for i, loc in enumerate(clusters[idx])])

        if cluster_start_time < minimal_time_to_start:
            minimal_time_to_start = cluster_start_time
            nearest_cluster = idx

    # Choose the best customer within the selected cluster based on priority
    if nearest_cluster is not None:
        best_time_priority = float('inf')
        best_node = None
        for customer_idx, customer in enumerate(clusters[nearest_cluster]):
            customer_priority = time_window_priority(time_windows[customer_idx], current_time + calculate_travel_time(cur_truck_pos, customer))
            if customer_priority < best_time_priority:
                best_time_priority = customer_priority
                best_node = customer_idx

    else:
        best_node = None  # No valid clusters or customers found, recommend a wait

    return best_node
